87	/**
88	 * RedesignedWorkspace — composition route for the §11–§17 chrome.
89	 *
90	 * Mounted at `/redesign`. Reads from `useBimStore` (same data as the
91	 * legacy `Workspace.tsx`) so engineers can A/B compare the two surfaces
92	 * without forking state. The canvas slot reuses the existing `Viewport`
93	 * / `PlanCanvas` components — only the chrome (TopBar / LeftRail /
94	 * Inspector / StatusBar / ToolPalette) is new.
95	 *
96	 * Spec sections wired here: §7 modes (1–7), §8 layout grid, §11 TopBar,
97	 * §12 Project Browser, §13 Inspector, §16 Tool palette, §17 StatusBar.
98	 */
99	
100	function mapComments(rows: Record<string, unknown>[]): UxComment[] {
101	  return rows.map((row) => ({
102	    id: String(row.id ?? ''),
103	    userDisplay: String(row.userDisplay ?? row.user_display ?? ''),
104	    body: String(row.body ?? ''),
105	    elementId: (row.elementId ?? row.element_id ?? null) as string | null,
106	    levelId: (row.levelId ?? row.level_id ?? null) as string | null,
107	    anchorXMm:
108	      row.anchorXMm !== undefined
109	        ? Number(row.anchorXMm)
110	        : row.anchor_x_mm !== undefined
111	          ? Number(row.anchor_x_mm)
112	          : null,
113	    anchorYMm:
114	      row.anchorYMm !== undefined
115	        ? Number(row.anchorYMm)
116	        : row.anchor_y_mm !== undefined
117	          ? Number(row.anchor_y_mm)
118	          : null,
119	    resolved: Boolean(row.resolved),
120	    createdAt: String(row.createdAt ?? row.created_at ?? ''),
121	  }));
122	}
123	
124	const KNOWN_PLAN_TOOLS = new Set<ToolId>(['select', 'wall', 'door', 'window', 'room', 'dimension']);
125	
126	type LegacyPlanTool =
127	  | 'select'
128	  | 'wall'
129	  | 'door'
130	  | 'window'
131	  | 'room'
132	  | 'room_rectangle'
133	  | 'grid'
134	  | 'dimension';
135	
136	function toolIdToLegacy(tool: ToolId): LegacyPlanTool | null {
137	  if (KNOWN_PLAN_TOOLS.has(tool)) return tool as LegacyPlanTool;
138	  return null;
139	}
140	
141	function legacyToToolId(legacy: LegacyPlanTool): ToolId {
142	  if (legacy === 'room_rectangle') return 'room';
143	  if (legacy === 'grid') return 'select';
144	  return legacy as ToolId;
145	}
146	
147	export function RedesignedWorkspace(): JSX.Element {
148	  const elementsById = useBimStore((s) => s.elementsById);
149	  const hydrateFromSnapshot = useBimStore((s) => s.hydrateFromSnapshot);
150	  const viewerMode = useBimStore((s) => s.viewerMode);
151	  const setViewerMode = useBimStore((s) => s.setViewerMode);
152	  const planTool = useBimStore((s) => s.planTool);
153	  const setPlanTool = useBimStore((s) => s.setPlanTool);
154	  const selectedId = useBimStore((s) => s.selectedId);
155	  const select = useBimStore((s) => s.select);
156	  const activeLevelId = useBimStore((s) => s.activeLevelId);
157	  const setActiveLevelId = useBimStore((s) => s.setActiveLevelId);
158	  const planHudMm = useBimStore((s) => s.planHudMm);
159	  const viewerCategoryHidden = useBimStore((s) => s.viewerCategoryHidden);
160	  const toggleViewerCategoryHidden = useBimStore((s) => s.toggleViewerCategoryHidden);
161	  const viewerClipElevMm = useBimStore((s) => s.viewerClipElevMm);
162	  const setViewerClipElevMm = useBimStore((s) => s.setViewerClipElevMm);
163	  const viewerClipFloorElevMm = useBimStore((s) => s.viewerClipFloorElevMm);
164	  const setViewerClipFloorElevMm = useBimStore((s) => s.setViewerClipFloorElevMm);
165	  const activeViewpointId = useBimStore((s) => s.activeViewpointId);
166	  const presencePeers = useBimStore((s) => s.presencePeers);
167	  const userDisplayName = useBimStore((s) => s.userDisplayName);
168	  const modelId = useBimStore((s) => s.modelId);
169	  const comments = useBimStore((s) => s.comments);
170	  const revision = useBimStore((s) => s.revision);
171	  const setComments = useBimStore((s) => s.setComments);
172	
173	  const [mode, setMode] = useState<WorkspaceMode>(() =>
174	    viewerMode === 'orbit_3d' ? '3d' : 'plan',
175	  );
176	  const [theme, setTheme] = useState<Theme>(() => (getCurrentTheme() as Theme) ?? 'light');
177	  const [paletteOpen, setPaletteOpen] = useState(false);
178	  const [cheatsheetOpen, setCheatsheetOpen] = useState(false);
179	  const [recentCommandIds, setRecentCommandIds] = useState<string[]>([]);
180	  const [tourOpen, setTourOpen] = useState<boolean>(() => !readOnboardingProgress().completed);
181	  const [seedLoading, setSeedLoading] = useState(false);
182	  const [seedError, setSeedError] = useState<string | null>(null);
183	  const [collaborationConflictQueue, setCollaborationConflictQueue] =
184	    useState<CollaborationConflictQueueV1 | null>(null);
185	  const [projectMenuOpen, setProjectMenuOpen] = useState(false);
186	  const [commentsOpen, setCommentsOpen] = useState(false);
187	  const [recentProjects, setRecentProjects] = useState<ProjectMenuItemRecent[]>(() =>
188	    readRecentProjects().map((r) => ({ id: r.id, label: r.label })),
189	  );
190	  const projectNameRef = useRef<HTMLButtonElement | null>(null);
191	  const planCameraHandleRef = useRef<PlanCameraHandle | null>(null);
192	  const [tabsState, setTabsState] = useState<TabsState>(() => readPersistedTabs() ?? EMPTY_TABS);
193	
194	  /** Persist tabs on every change (T-06). */
195	  useEffect(() => {
196	    persistTabs(tabsState);
197	  }, [tabsState]);
198	
199	  /* ── Tab helpers (§11.3) ──────────────────────────────────────────── */
200	  const activeTab: ViewTab | null = useMemo(
201	    () =>
202	      tabsState.activeId ? tabsState.tabs.find((t) => t.id === tabsState.activeId) ?? null : null,
203	    [tabsState],
204	  );
205	
206	  const handleTabActivate = useCallback(
207	    (id: string) => {
208	      let pendingPlanCamera: ViewportSnapshot['planCamera'] | undefined;
209	
210	      setTabsState((s) => {
211	        if (s.activeId === id) return s;
212	        // Snapshot the outgoing tab's viewport state so it can be restored
213	        // when the user comes back. T-07.
214	        let snapshotted = s;
215	        if (s.activeId) {
216	          const outgoing = s.tabs.find((x) => x.id === s.activeId);
217	          if (outgoing) {
218	            if (outgoing.kind === '3d' || outgoing.kind === 'plan-3d') {
219	              const pose = useBimStore.getState().orbitCameraPoseMm;
220	              if (pose) {
221	                snapshotted = snapshotViewport(snapshotted, s.activeId, {
222	                  ...(outgoing.viewportState ?? {}),
223	                  orbitCameraPoseMm: { eyeMm: pose.position, targetMm: pose.target },
224	                });
225	              }
226	            }
227	            // Snapshot the 2D plan camera for plan tabs (T-07 follow-up).
228	            if (outgoing.kind === 'plan' || outgoing.kind === 'plan-3d') {
229	              const planSnap = planCameraHandleRef.current?.getSnapshot();
230	              if (planSnap) {
231	                snapshotted = snapshotViewport(snapshotted, s.activeId, {
232	                  ...(snapshotted.tabs.find((x) => x.id === s.activeId)?.viewportState ?? {}),
233	                  planCamera: planSnap,
234	                });
235	              }
236	            }
237	          }
238	        }
239	        const next = activateTab(snapshotted, id);
240	        const t = next.tabs.find((x) => x.id === id);
241	        if (!t) return next;
242	        // Keep the store's active level in sync with the active tab's target.
243	        if ((t.kind === 'plan' || t.kind === 'plan-3d') && t.targetId) {
244	          setActiveLevelId(t.targetId);
245	        }
246	        // Restore the incoming tab's 3D camera, if it has one.
247	        const restored = t.viewportState?.orbitCameraPoseMm;
248	        if (restored?.eyeMm && restored.targetMm) {
249	          useBimStore.getState().setOrbitCameraFromViewpointMm({
250	            position: restored.eyeMm,
251	            target: restored.targetMm,
252	            up: { xMm: 0, yMm: 1, zMm: 0 },
253	          });
254	        }
255	        // Capture the incoming plan camera for post-setState apply (plan-to-plan case).
256	        if (t.kind === 'plan' || t.kind === 'plan-3d') {
257	          pendingPlanCamera = t.viewportState?.planCamera;
258	        }
259	        return next;
260	      });
261	
262	      // Apply plan camera to the already-mounted PlanCanvas (plan-to-plan switch).
263	      // For 3D→plan switches, initialCamera prop handles restore at mount time.
264	      if (pendingPlanCamera) {
265	        planCameraHandleRef.current?.applySnapshot(pendingPlanCamera);
266	      }
267	    },
268	    [setActiveLevelId],
269	  );
270	
271	  const handleTabClose = useCallback((id: string) => {
272	    setTabsState((s) => closeTab(s, id));
273	  }, []);
274	
275	  const openTabFromElement = useCallback((el: Element) => {
276	    const partial = tabFromElement(el);
277	    if (!partial) return;
278	    setTabsState((s) => openTab(s, partial));
279	  }, []);
280	
281	  /* ── Project menu handlers (T-03) ─────────────────────────────────── */
282	  const handleSaveSnapshot = useCallback(() => {
283	    const st = useBimStore.getState();
284	    if (!st.modelId) {
285	      setSeedError('Nothing to save — bootstrap a model first.');
286	      return;
287	    }
288	    const snap: Snapshot = {
289	      modelId: st.modelId,
290	      revision: st.revision ?? 0,
291	      elements: st.elementsById as unknown as Record<string, unknown>,
292	      violations: [],
293	    };
294	    const payload = buildSnapshotPayload(snap);
295	    downloadSnapshot(payload);
296	    const next = pushRecentProject(payload);
297	    setRecentProjects(next.map((r) => ({ id: r.id, label: r.label })));
298	  }, []);
299	
300	  const handleRestoreSnapshot = useCallback(
301	    async (file: File): Promise<void> => {
302	      try {
303	        const payload = await readSnapshotFile(file);
304	        hydrateFromSnapshot(payload.snapshot);
305	        const next = pushRecentProject(payload);
306	        setRecentProjects(next.map((r) => ({ id: r.id, label: r.label })));
307	      } catch (err) {
308	        setSeedError(err instanceof Error ? err.message : 'Failed to read snapshot');
309	      }
310	    },
311	    [hydrateFromSnapshot],
312	  );
313	
314	  const handlePickRecent = useCallback(
315	    (id: string) => {
316	      const found = findRecentProject(id);
317	      if (!found) return;
318	      hydrateFromSnapshot(found.payload.snapshot);
319	    },
320	    [hydrateFromSnapshot],
321	  );
322	
323	  const handleNewClear = useCallback(() => {
324	    hydrateFromSnapshot({ modelId: 'empty', revision: 0, elements: {}, violations: [] });
325	    setTabsState(EMPTY_TABS);
326	  }, [hydrateFromSnapshot]);
327	
328	  /* ── Comments + presence handlers (T-16) ─────────────────────────── */
329	  const handleCommentPost = useCallback(
330	    async (body: string): Promise<void> => {
331	      if (!modelId) return;
332	      await postComment(modelId, {
333	        userDisplay: userDisplayName || 'Guest',
334	        body,
335	        levelId: activeLevelId ?? undefined,
336	        elementId: selectedId ?? undefined,
337	      });
338	      const c = await fetchComments(modelId);
339	      setComments(mapComments((c.comments ?? []) as Record<string, unknown>[]));
340	    },
341	    [modelId, userDisplayName, activeLevelId, selectedId, setComments],
342	  );
343	
344	  const handleCommentResolve = useCallback(
345	    async (commentId: string, resolved: boolean): Promise<void> => {
346	      if (!modelId) return;
347	      await patchCommentResolved(modelId, commentId, resolved);
348	      const c = await fetchComments(modelId);
349	      setComments(mapComments((c.comments ?? []) as Record<string, unknown>[]));
350	    },
351	    [modelId, setComments],
352	  );
353	
354	  /* ── Semantic command dispatch (from PlanCanvas / Viewport) ────────── */
355	  const onSemanticCommand = useCallback(
356	    async (cmd: Record<string, unknown>): Promise<void> => {
357	      const mid = useBimStore.getState().modelId;
358	      const uid = useBimStore.getState().userId;
359	      if (!mid) return;
360	      try {
361	        const r = await applyCommand(mid, cmd, { userId: uid });
362	        if (r.revision !== undefined) {
363	          hydrateFromSnapshot({
364	            modelId: mid,
365	            revision: r.revision,
366	            elements: r.elements ?? {},
367	            violations: (r.violations ?? []) as Violation[],
368	          });
369	        }
370	        setCollaborationConflictQueue(null);
371	      } catch (err) {
372	        if (err instanceof ApiHttpError && err.status === 409) {
373	          setCollaborationConflictQueue(buildCollaborationConflictQueueV1(err.detail));
374	        } else {
375	          setCollaborationConflictQueue(null);
376	          setSeedError(err instanceof Error ? err.message : 'Apply failed');
377	        }
378	      }
379	    },
380	    [hydrateFromSnapshot],
381	  );
382	
383	  const persistViewpointHiddenKinds = useCallback(async () => {
384	    const st = useBimStore.getState();
385	    const vid = st.activeViewpointId;
386	    if (!vid || st.viewerMode !== 'orbit_3d') return;
387	    const hidden = VIEWER_HIDDEN_KIND_KEYS.filter((k) => st.viewerCategoryHidden[k]);
388	    await onSemanticCommand({
389	      type: 'updateElementProperty',
390	      elementId: vid,
391	      key: 'hiddenSemanticKinds3d',
392	      value: JSON.stringify(hidden),
393	    });
394	  }, [onSemanticCommand]);
395	
396	  const persistViewpointClipPlanes = useCallback(async () => {
397	    const st = useBimStore.getState();
398	    const vid = st.activeViewpointId;
399	    if (!vid || st.viewerMode !== 'orbit_3d') return;
400	    await onSemanticCommand({
401	      type: 'updateElementProperty',
402	      elementId: vid,
403	      key: 'viewerClipCapElevMm',
404	      value: st.viewerClipElevMm == null ? '' : String(st.viewerClipElevMm),
405	    });
406	    await onSemanticCommand({
407	      type: 'updateElementProperty',
408	      elementId: vid,
409	      key: 'viewerClipFloorElevMm',
410	      value: st.viewerClipFloorElevMm == null ? '' : String(st.viewerClipFloorElevMm),
411	    });
412	  }, [onSemanticCommand]);
413	
414	  const insertSeedHouse = useCallback(async (): Promise<void> => {
415	    setSeedLoading(true);
416	    setSeedError(null);
417	    try {
418	      const bx = await bootstrap();
419	      const pj = bx.projects as Record<string, unknown>[] | undefined;
420	      const m0 = pj?.[0]?.models as Array<{ id?: unknown }> | undefined;
421	      const mid = m0?.[0]?.id;
422	      if (typeof mid !== 'string') throw new Error('No models — run make seed');
423	      const snapRes = await fetch(`/api/models/${encodeURIComponent(mid)}/snapshot`);
424	      if (!snapRes.ok) throw new Error(`snapshot ${snapRes.status}`);
425	      const snap = (await snapRes.json()) as Snapshot;
426	      hydrateFromSnapshot(snap);
427	    } catch (err) {
428	      setSeedError(err instanceof Error ? err.message : 'Failed to load seed');
429	    } finally {
430	      setSeedLoading(false);
431	    }
432	  }, [hydrateFromSnapshot]);
433	
434	  useEffect(() => {
435	    const isEmpty = Object.keys(elementsById).length === 0;
436	    if (!isEmpty) return;
437	    void insertSeedHouse();
438	    // Run-once bootstrap: re-running is the user's job via the empty-state CTA.
439	    // eslint-disable-next-line react-hooks/exhaustive-deps
440	  }, []);
441	
442	  // After the seed has hydrated, prune any restored tabs whose targets
443	  // no longer exist (e.g. a sheet deleted between sessions). If the
444	  // pruned set is empty, open a default Plan tab on the first level.
445	  // Runs once when the store transitions from empty → non-empty.
446	  const seededRef = useRef(false);
447	  useEffect(() => {
448	    if (seededRef.current) return;
449	    if (Object.keys(elementsById).length === 0) return;
450	    seededRef.current = true;
451	    setTabsState((s) => {
452	      const pruned = pruneTabsAgainstElements(s, elementsById);
453	      if (pruned.tabs.length > 0) return pruned;
454	      const levels = (Object.values(elementsById) as Element[]).filter(
455	        (e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level',
456	      );
457	      if (levels.length === 0) return pruned;
458	      const targetLevel =
459	        levels.find((l) => l.id === activeLevelId) ??
460	        levels.sort((a, b) => a.elevationMm - b.elevationMm)[0];
461	      if (!targetLevel) return pruned;
462	      return openTab(pruned, {
463	        kind: 'plan',
464	        targetId: targetLevel.id,
465	        label: `Plan · ${targetLevel.name}`,
466	      });
467	    });
468	  }, [elementsById, activeLevelId]);
469	
470	  /* ── Mode wiring (§7 + §20) ────────────────────────────────────────── */
471	  const handleModeChange = useCallback(
472	    (next: WorkspaceMode) => {
473	      setMode(next);
474	      if (next === 'plan' || next === 'plan-3d') setViewerMode('plan_canvas');
475	      else if (next === '3d') setViewerMode('orbit_3d');
476	      // Activate or open a tab of the matching kind so the canvas
477	      // mounts the right view.
478	      setTabsState((s) => {
479	        const fallback = defaultTabFallbackForKind(next, elementsById, activeLevelId);
480	        if (!fallback) return s;
481	        return activateOrOpenKind(s, next as TabKind, fallback);
482	      });
483	    },
484	    [setViewerMode, elementsById, activeLevelId],
485	  );
486	
487	  /* ── Global hotkeys: 1–7 modes, ?, V/W/D/M/S/etc tools ─────────────── */
488	  useEffect(() => {
489	    const onKey = (event: globalThis.KeyboardEvent): void => {
490	      const target = event.target as HTMLElement | null;
491	      if (target) {
492	        const tag = target.tagName;
493	        if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
494	        if (target.isContentEditable) return;
495	      }
496	      const fromMode = modeForHotkey(event.key);
497	      if (fromMode) {
498	        event.preventDefault();
499	        handleModeChange(fromMode);
500	        return;
501	      }
502	      if (event.key === '?') {
503	        event.preventDefault();
504	        setCheatsheetOpen((v) => !v);
505	        return;
506	      }
507	      if ((event.key === 'k' || event.key === 'K') && (event.metaKey || event.ctrlKey)) {
508	        event.preventDefault();
509	        setPaletteOpen((v) => !v);
510	        return;
511	      }
512	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
513	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
514	        event.preventDefault();
515	        setTabsState((s) => cycleActive(s, event.shiftKey ? 'backward' : 'forward'));
516	        return;
517	      }
518	      // Close active tab — Ctrl/⌘+W.
519	      if ((event.key === 'w' || event.key === 'W') && (event.metaKey || event.ctrlKey)) {
520	        event.preventDefault();
521	        setTabsState((s) => (s.activeId ? closeTab(s, s.activeId) : s));
522	        return;
523	      }
524	      // Tool hotkeys — match the spec'd letters from TOOL_REGISTRY.
525	      const upper = event.key.length === 1 ? event.key.toUpperCase() : event.key;
526	      const hotkeyLabel = event.shiftKey ? `Shift+${upper}` : upper;
527	      const tool = (Object.values(TOOL_REGISTRY) as { id: ToolId; hotkey: string }[]).find(
528	        (t) => t.hotkey === hotkeyLabel,
529	      );
530	      if (tool) {
531	        const legacy = toolIdToLegacy(tool.id);
532	        if (legacy) {
533	          event.preventDefault();
534	          setPlanTool(legacy);
535	        }
536	      }
537	    };
538	    document.addEventListener('keydown', onKey);
539	    return () => document.removeEventListener('keydown', onKey);
540	  }, [handleModeChange, setPlanTool]);
541	
542	  /* ── Project Browser sections ─────────────────────────────────────── */
543	  const browserSections = useMemo<LeftRailSection[]>(() => {
544	    const levels = (Object.values(elementsById) as Element[])
