1	import type { PerspectiveId, Violation } from '@bim-ai/core';
2	
3	import { Btn } from '@bim-ai/ui';
4	
5	import {
6	  groupViolationsBySeverity,
7	  recommendedContextForRuleId,
8	  sortViolationsDeterministic,
9	  summarizeQuickFixCommand,
10	} from './advisorViolationContext';
11	import { filterViolationsForPerspective } from './perspectiveFilter';
12	
13	export function AdvisorPanel(props: {
14	  violations: Violation[];
15	  selectionId?: string;
16	  preset: string;
17	  onPreset: (preset: string) => void;
18	  codePresets?: string[];
19	  onApplyQuickFix(cmd: Record<string, unknown>): void;
20	  perspective: PerspectiveId;
21	}) {
22	  const scoped = props.selectionId
23	    ? props.violations.filter((v) => (v.elementIds ?? []).includes(props.selectionId!))
24	    : props.violations;
25	
26	  const filtered = filterViolationsForPerspective(scoped, props.perspective);
27	  const sorted = sortViolationsDeterministic(filtered);
28	  const grouped = groupViolationsBySeverity(sorted);
29	  const presetKeys = props.codePresets ?? ['residential', 'commercial', 'office'];
30	
31	  function renderViolationCard(v: Violation, i: number) {
32	    const qf =
33	      v.quickFixCommand && typeof v.quickFixCommand === 'object'
34	        ? summarizeQuickFixCommand(v.quickFixCommand as Record<string, unknown>)
35	        : null;
36	    const ctx = recommendedContextForRuleId(v.ruleId);
37	
38	    return (
39	      <li key={`${v.ruleId}-${i}-${v.message.slice(0, 24)}`} className="rounded border p-2">
40	        <div className="flex flex-wrap items-center gap-2">
41	          <span
42	            className={`rounded px-2 py-0.5 text-[10px] ${v.blocking ? 'bg-red-500/25' : 'bg-amber-500/15'}`}
43	          >
44	            {v.severity}
45	          </span>
46	          <span className="font-mono text-[10px] text-muted">{v.ruleId}</span>
47	
48	          {v.discipline ? (
49	            <span className="rounded bg-muted/30 px-1 py-0.5 text-[9px] text-muted">
50	              {v.discipline}
51	            </span>
52	          ) : null}
53	        </div>
54	
55	        <div className="mt-1">{v.message}</div>
56	
57	        <p className="mt-1 text-[10px] text-muted">{ctx}</p>
58	
59	        {(v.elementIds?.length ?? 0) > 0 ? (
60	          <div className="mt-1 text-[10px]">
61	            <span className="text-muted">elementIds: </span>
62	            <code className="break-all text-[10px]">{(v.elementIds ?? []).join(', ')}</code>
63	          </div>
64	        ) : null}
65	
66	        {qf ? (
67	          <div className="mt-2 rounded border border-border/50 bg-muted/5 p-2">
68	            <div className="text-[9px] font-semibold text-muted">Quick-fix command (summary)</div>
69	            <ul className="mt-1 list-inside list-disc font-mono text-[9px] text-muted">
70	              {qf.map((line) => (
71	                <li key={line} className="break-all">
72	                  {line}
73	                </li>
74	              ))}
75	            </ul>
76	            <p className="mt-1 text-[9px] text-muted">
77	              Applying still requires an explicit click below — nothing runs automatically.
78	            </p>
79	          </div>
80	        ) : null}
81	
82	        {v.quickFixCommand && typeof v.quickFixCommand === 'object' ? (
83	          <Btn
84	            type="button"
85	            className="mt-2 px-3 py-1 text-[11px]"
86	            variant="quiet"
87	            onClick={() => props.onApplyQuickFix(v.quickFixCommand as Record<string, unknown>)}
88	          >
89	            Apply suggested fix
90	          </Btn>
91	        ) : null}
92	      </li>
93	    );
94	  }
95	
96	  return (
97	    <div className="space-y-2">
98	      <div className="flex flex-wrap items-center gap-2 text-[11px]">
99	        <span className="text-muted">Code preset</span>
100	        <select
101	          value={props.preset}
102	          onChange={(e) => props.onPreset(e.target.value)}
103	          className="rounded border border-border bg-background px-2 py-1"
104	        >
105	          {presetKeys.map((k) => (
106	            <option key={k} value={k}>
107	              {k}
108	            </option>
109	          ))}
110	        </select>
111	
112	        <span className="text-muted">Perspective</span>
113	        <span className="rounded border border-border px-2 py-0.5 font-mono text-[10px]">
114	          {props.perspective}
115	        </span>
116	      </div>
117	
118	      {grouped.length ? (
119	        <div className="max-h-[40vh] space-y-3 overflow-auto text-xs">
120	          {grouped.map((g) => (
121	            <div key={g.severity}>
122	              <div className="mb-1 text-[10px] font-semibold uppercase tracking-wide text-muted">
123	                {g.severity}
124	              </div>
125	              <ul className="space-y-2">{g.items.map((v, i) => renderViolationCard(v, i))}</ul>
126	            </div>
127	          ))}
128	        </div>
129	      ) : (
130	        <div className="rounded border bg-surface p-4 text-[11px] text-muted">
131	          {props.selectionId
132	            ? 'No advisory items for selection.'
133	            : 'No advisory items — keep sketching!'}
134	        </div>
135	      )}
136	    </div>
137	  );
138	}
